/**
 * Cross-language MeasFlow benchmarks (C binding).
 *
 * Measures write/read performance for the C implementation and optionally
 * reads files generated by C# or Python to verify cross-language compatibility.
 *
 * Build:
 *   cmake -B build -S c -DMEAS_BUILD_BENCHMARKS=ON
 *   cmake --build build --config Release
 *   ./build/bench_cross_language
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include "../measflow.h"

#ifdef _WIN32
#include <windows.h>
static double now_ms(void)
{
    LARGE_INTEGER freq, cnt;
    QueryPerformanceFrequency(&freq);
    QueryPerformanceCounter(&cnt);
    return (double)cnt.QuadPart / (double)freq.QuadPart * 1000.0;
}
#else
static double now_ms(void)
{
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec * 1000.0 + ts.tv_nsec / 1e6;
}
#endif

typedef struct {
    double median_ms;
    double min_ms;
    double max_ms;
} BenchResult;

static int cmp_double(const void *a, const void *b)
{
    double da = *(const double *)a, db = *(const double *)b;
    return (da > db) - (da < db);
}

static BenchResult run_bench(void (*fn)(const char *, const float *, int),
                              const char *path, const float *data, int n,
                              int warmup, int iterations)
{
    int i;
    for (i = 0; i < warmup; i++)
        fn(path, data, n);

    double *times = (double *)malloc((size_t)iterations * sizeof(double));
    for (i = 0; i < iterations; i++) {
        double t0 = now_ms();
        fn(path, data, n);
        times[i] = now_ms() - t0;
    }
    qsort(times, (size_t)iterations, sizeof(double), cmp_double);

    BenchResult r;
    r.median_ms = times[iterations / 2];
    r.min_ms = times[0];
    r.max_ms = times[iterations - 1];
    free(times);
    return r;
}

static void do_write(const char *path, const float *data, int n)
{
    MeasWriter *w = meas_writer_open(path);
    MeasGroupWriter *g = meas_writer_add_group(w, "Data");
    MeasChannelWriter *ch = meas_group_add_channel(g, "Signal", MEAS_FLOAT32);
    meas_channel_write_f32(ch, data, n);
    meas_writer_close(w);
}

static void do_stream(const char *path, const float *data, int n)
{
    MeasWriter *w = meas_writer_open(path);
    MeasGroupWriter *g = meas_writer_add_group(w, "Data");
    MeasChannelWriter *ch = meas_group_add_channel(g, "Signal", MEAS_FLOAT32);
    int chunk = n / 10;
    int i;
    for (i = 0; i < 10; i++) {
        meas_channel_write_f32(ch, data + i * chunk, chunk);
        meas_writer_flush(w);
    }
    meas_writer_close(w);
}

static void do_read(const char *path, const float *data, int n)
{
    (void)data;
    MeasReader *r = meas_reader_open(path);
    if (!r) return;
    const MeasGroupData *grp = meas_reader_group_by_name(r, "Data");
    if (grp) {
        const MeasChannelData *ch = meas_group_channel_by_name(grp, "Signal");
        if (ch) {
            float *buf = (float *)malloc((size_t)n * sizeof(float));
            meas_channel_read_f32(ch, buf, n);
            free(buf);
        }
    }
    meas_reader_close(r);
}

static long file_size(const char *path)
{
    FILE *f = fopen(path, "rb");
    if (!f) return 0;
    fseek(f, 0, SEEK_END);
    long sz = ftell(f);
    fclose(f);
    return sz;
}

int main(void)
{
    int sample_counts[] = { 100000, 1000000 };
    int num_counts = 2;
    int s;

    for (s = 0; s < num_counts; s++) {
        int n = sample_counts[s];

        float *data = (float *)malloc((size_t)n * sizeof(float));
        srand(42);
        for (int i = 0; i < n; i++)
            data[i] = (float)rand() / (float)RAND_MAX * 10000.0f;

        char path[256];
        snprintf(path, sizeof(path), "c_%d.meas", n);

        printf("\n============================================================\n");
        printf("  Cross-language benchmarks (C) -- %d samples\n", n);
        printf("============================================================\n");

        BenchResult r;

        r = run_bench(do_write, path, data, n, 1, 5);
        printf("\n  Write (C):         %8.2f ms\n", r.median_ms);

        r = run_bench(do_stream, path, data, n, 1, 5);
        printf("  Stream (C):        %8.2f ms  (10 flushes)\n", r.median_ms);

        /* Prepare file for read */
        do_write(path, data, n);
        r = run_bench(do_read, path, data, n, 1, 5);
        printf("  Read (C):          %8.2f ms\n", r.median_ms);

        printf("\n  File size:         %8.1f KB\n", file_size(path) / 1024.0);

        /* Try reading files from other languages */
        {
            char cross_path[256];
            snprintf(cross_path, sizeof(cross_path), "csharp_%d.meas", n);
            MeasReader *cr = meas_reader_open(cross_path);
            if (cr) {
                meas_reader_close(cr);
                r = run_bench(do_read, cross_path, data, n, 1, 5);
                printf("  Read C# file:      %8.2f ms\n", r.median_ms);
            }

            snprintf(cross_path, sizeof(cross_path), "py_%d.meas", n);
            cr = meas_reader_open(cross_path);
            if (cr) {
                meas_reader_close(cr);
                r = run_bench(do_read, cross_path, data, n, 1, 5);
                printf("  Read Python file:  %8.2f ms\n", r.median_ms);
            }
        }

        remove(path);
        free(data);
    }

    return 0;
}
